-- Register accepted Layer 4 EventOverlayModel event-context vector score families.
-- These are reviewed core event-context state_vector_value tokens, not source table
-- columns, event-artifact fields, alpha confidence, trading signal, expression, or
-- final-action outputs.

ON CONFLICT (id) DO UPDATE SET
  kind = EXCLUDED.kind,
  key = EXCLUDED.key,
  payload_format = EXCLUDED.payload_format,
  payload = EXCLUDED.payload,
  path = EXCLUDED.path,
  applies_to = EXCLUDED.applies_to,
  artifact_sync_policy = EXCLUDED.artifact_sync_policy,
  note = EXCLUDED.note;
